INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('immigration-1aab856d-moex-00190', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '關於刑法第213條「公務員登載不實罪」之敘述，下列何者錯誤？', '["公務員必須對所登載之公文書具有製作之權限，始能成立「公務員登載不實罪」", "如公務員對不具修改權限之公文書擅自更改內容，亦成立「公務員登載不實罪」", "「公務員登載不實罪」亦得以不作為之方式實行", "公務員「明知」為不實事實而登載於所掌之公文書時，始能成立「公務員登載不實罪」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00191', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '下列有關刑事訴訟法第131條第2項「緊急搜索」之描述，何者正確？', '["是屬於對人的搜索，目的是在逮捕被告、犯罪嫌疑人或執行拘提、羈押", "執行搜索完畢後三日內應向該管檢察署檢察官及法院陳報，法院未予撤銷者，所扣得之物品當 然即有證據能力", "應由檢察官親自為之，或由檢察官指揮司法警察（官）執行搜索", "檢察官指揮司法警察（官）執行搜索者，應由司法警察（官）提出偵查報告，報請檢察官書面 核准，不得口頭聲請"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00192', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '某甲施用搖頭丸後，於騎機車返家途中，因藥力發作，在路旁昏睡，警方獲報到場，見甲身旁有 搖頭丸2粒，以現行犯逮捕某甲後，下列敘述何者錯誤？', '["警察可以對某甲隨身攜帶的背包進行搜索", "警察可以徵得某甲同意後，前往某甲家中進行搜索", "警察可以對某甲停放在住處樓下的轎車進行搜索", "警察可以對某甲騎乘的機車置物箱進行搜索"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00193', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '下列有關緩起訴之敘述，何者正確？', '["被告於緩起訴期間內，故意犯有期徒刑以上刑之罪，經檢察官提起公訴者，檢察官得依職權或 依告訴人之聲請撤銷原處分，繼續偵查或起訴", "告訴人接受不起訴或緩起訴處分書後，得於20日內以書狀敘述不服之理由，經原檢察官向直 接上級檢察署檢察長或檢察總長聲請再議", "檢察官為緩起訴後，應依職權逕送直接上級檢察署檢察長或檢察總長再議", "被告所犯為死刑、無期徒刑或最輕本刑3年以上有期徒刑以外之罪，檢察官認以緩起訴為適當 者，得定2年以上5年以下之緩起訴期間，為緩起訴處分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00194', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '某甲因殺人案經檢察官偵辦，並由檢察官向法院聲請羈押獲准，嗣後檢察官向法院起訴，並由法 院裁定某甲羈押，下列敘述何者正確？', '["偵查中羈押不得逾3月", "延長羈押，第一審、第二審以6次為限，第三審以1次為限", "偵查及審判中之羈押期間，累計不得逾5年", "某甲於審判中若經具保停止羈押，其後又因勾串共犯或證人，經法院再執行羈押，再執行羈押 之期間，應更新計算"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00195', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '下列有關管轄之敘述，何者正確？', '["被告若在監服刑，服刑監獄所在地之法院「並無」管轄權", "某甲家住基隆，於住家附近偷一台機車，欲騎往臺中找女友，於桃園為警攔查，臺中地院「有」 管轄權", "某甲家住高雄，在網路上對於家住臺中之某乙誹謗，臺北地院「並無」管轄權", "數被告共犯A罪，其中一名被告又於甲地犯B罪，甲地法院對於A罪「有」管轄權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00196', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '法院審酌違背法定程序所取得證據之證據能力時，下列何者並非應考量之因素？', '["違背法定程序之情節", "犯罪所生之危險或實害", "偵審人員如依法定程序有無發現該證據之必然性", "證據對於證明犯罪事實之證據價值"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "efb746b710a8", "answer_pdf_sha1": "b044dfb9d125", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00197', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-13504c0c', 'sub-immigration-1aab856d-03', NULL, 'single_choice', '下列敘述，何者沒有冗詞贅語？', '["這箱東西顯得太重了，我無法拿得起來", "選舉投票日將屆，各候選人無不卯足全力衝刺，以爭取更多選票", "捷運上午接二連三發生跳電二十多分鐘的情況不斷持續，許多旅客等了半小時還 等不到車", "關於本次美軍空襲阿富汗的事件，記者在現場為您轉播來自 CNN的本臺第一手 獨家新聞報導"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "7f66cde420d8", "answer_pdf_sha1": "aff3d92b6589", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00198', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-13504c0c', 'sub-immigration-1aab856d-03', NULL, 'single_choice', '「在狂暴自然與無情時間中消磨，千年來屹立不搖的努比亞金字塔，最後毀在人性 的貪婪與無知。一八三四年一名來自義大利、曾經加入蘇丹遠征軍的盜墓者費里尼， 在喀土穆服役期間，聽說沙漠中藏有許多未經發掘的古代寶藏，財迷心竅的他竟然 跑去說服當地統治者蘇丹總督，總督本人就是聲名狼藉的奴隸販子，對於異教徒所 遺留的偉大建築毫無感情可言，當然也不在乎金字塔即將面臨的悲劇。取得許可後 的費里尼帶了一大批工人，開始以不專業的手法在美羅埃挖掘。」 根據上文，下列敘述何者錯誤？', '["破壞努比亞金字塔的是義大利人", "努比亞金字塔位於蘇丹境內的沙漠之中", "當時總督為了錢，並不反對挖掘金字塔", "努比亞金字塔毀於時間的無情與人性的貪婪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "7f66cde420d8", "answer_pdf_sha1": "aff3d92b6589", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00199', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-13504c0c', 'sub-immigration-1aab856d-03', NULL, 'single_choice', '「每日晨禱，我與同仁們一起唸〈天主經〉，晚上睡前我則獨自唸《大悲咒》，迴 向給一切眾生作為一天的結束。忽然，我驚覺我正在體驗馬天賜神父過去的交談經 驗，他曾在菲律賓的醫院陪伴垂死之人，如今我在臺東唯一的安寧病房體驗生命。 馬神父在自己的宗教團體裡開啟宗教交談，我則是以佛教徒的身分在天主教機構裡 實踐宗教交談。我喜歡欣賞不同宗教之間的互動，但也維持著一定的距離。在不同 宗教團體裡的學習是連續性的，他們的一言一行不斷激盪著我的慣性思維。」 根據上文，下列選項何者正確？', '["在臺東安寧病房的體驗，顯示不同宗教雖有差異，但藉由彼此的互動學習，可互 相激盪啟發", "以佛教徒的身分穿梭在天主教機構裡，體會不同教義的不同美好，也使自己原本 的信仰更加堅定", "〈天主經〉與《大悲咒》都是外在的客觀知識，因此作者白天晚上分別閱讀念誦， 完全不會有矛盾", "因為「我」是佛教徒，跟不同宗教都必須維持一定的距離，只能勉力學習和別的 教徒交談並研讀其經典"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:54+00:00", "source_pdf_sha1": "7f66cde420d8", "answer_pdf_sha1": "aff3d92b6589", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
